"""offlinai_ai — interactive AI coding CLI for the CodeBench shell.

Talks to the Swift-side ``LlamaRunner`` through signal files. Protocol
matches ``offlinai_latex``:

    $TMPDIR/latex_signals/ai_request.json      Python writes, Swift reads + removes
    $TMPDIR/latex_signals/ai_response.stream   Swift appends tokens, Python tails
    $TMPDIR/latex_signals/ai_done.txt          Swift writes status + message
    $TMPDIR/latex_signals/current_editor_file.txt   Swift writes on every file load

The ``ai`` shell builtin opens a persistent REPL:

    $ ai                      # edit whatever file is in the editor
    $ ai path/to/file.py      # edit an explicit file
    ai> add type hints to all functions
    ai> /mode bypass          # auto-apply edits without asking
    ai> /model                # list / select the active GGUF
    ai> /usage                # tokens consumed this session
    ai> /quit                 # exit the REPL

Permission modes:

    nothing   — LLM can read but every write is refused
    allow     — every proposed edit shows a diff and asks y/n (default)
    plan      — LLM writes a multi-step plan, user edits it before any file is touched
    auto      — apply small edits (< 5 lines changed) automatically, large ones prompt
    bypass    — apply everything automatically, no prompts

All writes that actually touch disk also append to an audit log at
``$TMPDIR/latex_signals/ai_audit.log`` so a user can see exactly what
the assistant changed in a session.
"""

from __future__ import annotations

import difflib
import json
import os
import re
import shutil
import ssl
import sys
import tempfile
import time
import urllib.error
import urllib.request
from dataclasses import dataclass, field
from pathlib import Path
from typing import Callable, Iterable, Optional


# ----------------------------------------------------------------------
# SSL context — iOS Python doesn't auto-discover system certs. Building
# our own context with certifi's bundle (which IS bundled in the app)
# avoids a class of EXC_BAD_ACCESS crashes in OpenSSL that show up as
# "offlinai-repl: EXC_BAD_ACCESS (code=1, address=0x1)" — that's the
# SSL module trying to deref a nil cert store on iOS.
# ----------------------------------------------------------------------

_SSL_CONTEXT: Optional[ssl.SSLContext] = None


def _get_ssl_context() -> Optional[ssl.SSLContext]:
    """Create (once, cached) an SSL context using certifi's bundled CA
    list. Returns None if certifi isn't importable — caller should then
    fall back to no SSL (HTTP-only) or let urllib raise a clean error
    instead of segfaulting."""
    global _SSL_CONTEXT
    if _SSL_CONTEXT is not None:
        return _SSL_CONTEXT
    try:
        import certifi
        ctx = ssl.create_default_context(cafile=certifi.where())
    except BaseException as e:
        # BaseException — ssl.create_default_context calls into OpenSSL
        # which on iOS can terminate via C-level abort if the cert
        # store init fails hard; we want to surface it as a Python
        # error message, not a segfault.
        print(f"{_RED}  ssl init failed: {type(e).__name__}: {e}{_RESET}")
        return None
    _SSL_CONTEXT = ctx
    return ctx

# ANSI — match offlinai_shell's palette. Kept local so this module can
# be imported independently (e.g. from a one-off script) without pulling
# the full shell in.
_RESET = "\033[0m"
_BOLD  = "\033[1m"
_DIM   = "\033[2m"
_CYN   = "\033[36m"
_GRN   = "\033[32m"
_YLW   = "\033[33m"
_RED   = "\033[31m"
_MAG   = "\033[35m"
_BLU   = "\033[34m"


def _signal_dir() -> Path:
    p = Path(tempfile.gettempdir()) / "latex_signals"
    p.mkdir(parents=True, exist_ok=True)
    return p


def _models_dir() -> Path:
    """Cache dir for GGUF files pulled via the CLI.
    `~/Documents/Models/` is visible in the iOS Files app, so users
    can inspect / delete models there too."""
    p = Path.home() / "Documents" / "Models"
    p.mkdir(parents=True, exist_ok=True)
    return p


# ----------------------------------------------------------------------
# Model registry — Ollama-style shortname → (HuggingFace GGUF URL,
# approx size in MB).
#
# Scoped to the three Qwen3.5 sizes that fit on an iPad/iPhone at
# Q4_K_M quant (Qwen3.5 released 2026-03-02 — see
# https://huggingface.co/collections/unsloth/qwen35). GGUFs come
# from unsloth's mirror, which ships the canonical Q4_K_M files
# under predictable Qwen3.5-<size>-Q4_K_M.gguf names.
#
# Pass a direct https://…/foo.gguf URL to /pull for anything else.
# ----------------------------------------------------------------------

MODEL_REGISTRY: dict[str, tuple[str, int]] = {
    "qwen3.5:0.8b": (
        "https://huggingface.co/unsloth/Qwen3.5-0.8B-GGUF/resolve/main/Qwen3.5-0.8B-Q4_K_M.gguf",
        560,   # ≈ 0.8B × 0.7 B/param (Q4_K_M typical ratio)
    ),
    "qwen3.5:2b": (
        "https://huggingface.co/unsloth/Qwen3.5-2B-GGUF/resolve/main/Qwen3.5-2B-Q4_K_M.gguf",
        1400,
    ),
    "qwen3.5:4b": (
        "https://huggingface.co/unsloth/Qwen3.5-4B-GGUF/resolve/main/Qwen3.5-4B-Q4_K_M.gguf",
        2800,
    ),
}


def _list_registry() -> None:
    """Pretty-print the MODEL_REGISTRY.

    Scoped to Qwen3.5 (released 2026-03-02) at three sizes. For
    anything else, pass a full https://…/foo.gguf URL to /pull."""
    print(f"{_BOLD}Available models{_RESET}  {_DIM}(ai run <name>, /pull <name>){_RESET}")
    print(f"  {_MAG}Qwen3.5{_RESET}  {_DIM}(2026-03-02 release, Q4_K_M quant){_RESET}")
    for name, (_url, size_mb) in MODEL_REGISTRY.items():
        size_str = f"{size_mb / 1024:.1f} GB" if size_mb >= 1024 else f"{size_mb} MB"
        print(f"    {_CYN}{name:<16}{_RESET} {_DIM}~{size_str}{_RESET}")
    print()
    print(f"{_DIM}  Also accepts a direct https://…/foo.gguf URL "
          f"for anything not in this list.{_RESET}")


def _resolve_spec(spec: str) -> tuple[str, Path]:
    """Turn `spec` (ollama-style name OR HF URL) into (download_url, local_path)."""
    spec = spec.strip()
    if spec.startswith("http://") or spec.startswith("https://"):
        url = spec
        filename = os.path.basename(url.split("?")[0]) or "model.gguf"
    elif spec in MODEL_REGISTRY:
        url, _sz = MODEL_REGISTRY[spec]
        filename = spec.replace(":", "-").replace("/", "_") + ".gguf"
    else:
        raise ValueError(
            f"unknown model '{spec}'. Try `/pull` with no args to see the registry, "
            f"or pass a direct https://…/foo.gguf URL."
        )
    return url, _models_dir() / filename


def _human_bytes(n: int) -> str:
    for u in ("B", "KB", "MB", "GB"):
        if n < 1024 or u == "GB":
            return f"{n:,.0f} {u}" if u != "B" else f"{n} B"
        n /= 1024
    return f"{n:,.1f} TB"


def _format_eta(seconds: float) -> str:
    if seconds < 0 or seconds > 99 * 3600:
        return "??:??"
    m, s = divmod(int(seconds), 60)
    h, m = divmod(m, 60)
    return f"{h:02d}:{m:02d}:{s:02d}" if h else f"{m:02d}:{s:02d}"


def _download_model(url: str, dest: Path) -> bool:
    """Stream-download `url` to `dest` with a live progress bar.
    Supports resume if `dest.partial` already exists from an
    interrupted run. Returns True on success."""
    partial = dest.with_suffix(dest.suffix + ".partial")
    existing = partial.stat().st_size if partial.exists() else 0

    req = urllib.request.Request(url, headers={
        "User-Agent": "CodeBench-AI-CLI/1.0",
        "Accept": "application/octet-stream",
    })
    if existing > 0:
        req.add_header("Range", f"bytes={existing}-")
        print(f"{_DIM}  resuming at {_human_bytes(existing)}…{_RESET}")

    ssl_ctx = _get_ssl_context() if url.startswith("https://") else None
    if url.startswith("https://") and ssl_ctx is None:
        print(f"{_RED}  can't establish SSL context on this platform.{_RESET}")
        print(f"{_DIM}  Suggested fix:{_RESET}")
        print(f"  1) download the .gguf manually from: {url}")
        print(f"  2) save to ~/Documents/Models/")
        print(f"  3) re-run  /load <path>  inside the ai REPL")
        return False

    try:
        resp = urllib.request.urlopen(req, timeout=30, context=ssl_ctx)
    except urllib.error.HTTPError as e:
        # Some servers don't support range → retry from scratch
        if existing > 0 and e.code in (416, 400):
            partial.unlink()
            existing = 0
            req = urllib.request.Request(url, headers={"User-Agent": "CodeBench-AI-CLI/1.0"})
            try:
                resp = urllib.request.urlopen(req, timeout=30, context=ssl_ctx)
            except Exception as e2:
                print(f"{_RED}  download failed: {e2}{_RESET}")
                return False
        else:
            print(f"{_RED}  download failed: HTTP {e.code} {e.reason}{_RESET}")
            return False
    except Exception as e:
        print(f"{_RED}  download failed: {type(e).__name__}: {e}{_RESET}")
        if "CERTIFICATE" in str(e).upper() or "SSL" in str(e).upper():
            print(f"{_DIM}  SSL-related — trying again with unverified SSL (reduced security)…{_RESET}")
            try:
                unverified = ssl._create_unverified_context()
                resp = urllib.request.urlopen(req, timeout=30, context=unverified)
            except Exception as e2:
                print(f"{_RED}  retry failed: {e2}{_RESET}")
                return False
        else:
            return False

    # Content-Length for 206 responses gives REMAINING bytes, add
    # what we already have to reconstitute the full size.
    remaining = resp.headers.get("Content-Length")
    try:
        total = int(remaining) + existing if remaining else 0
    except ValueError:
        total = 0

    mode = "ab" if existing > 0 else "wb"
    chunk = 256 * 1024  # 256 KB
    downloaded = existing
    t0 = time.time()
    last_draw = 0.0

    try:
        with partial.open(mode) as fh:
            while True:
                data = resp.read(chunk)
                if not data:
                    break
                fh.write(data)
                downloaded += len(data)
                now = time.time()
                if now - last_draw >= 0.15 or downloaded == total:
                    last_draw = now
                    _draw_progress(downloaded, total, t0, existing)
        print()  # newline after final progress line
    except KeyboardInterrupt:
        print(f"\n{_YLW}  ^C — partial saved to {partial}, /pull <same> to resume{_RESET}")
        return False
    except Exception as e:
        print(f"\n{_RED}  download interrupted: {e}{_RESET}")
        return False

    # Atomic rename: partial → final
    try:
        partial.replace(dest)
    except OSError as e:
        print(f"{_RED}  rename failed: {e}{_RESET}")
        return False

    print(f"{_GRN}  ✓ saved {_human_bytes(downloaded)} → {dest}{_RESET}")
    return True


def _draw_progress(done: int, total: int, t0: float, resumed_from: int) -> None:
    """Redraw a single-line text progress bar. Uses \\r so it
    overwrites itself in place."""
    width = 28
    if total > 0:
        ratio = min(1.0, done / total)
        filled = int(ratio * width)
        bar = "█" * filled + "░" * (width - filled)
        pct = f"{ratio * 100:5.1f}%"
    else:
        # Unknown size — spin instead of bar
        spinner = "⠋⠙⠹⠸⠼⠴⠦⠧⠇⠏"[int(time.time() * 10) % 10]
        bar = spinner * width
        pct = "  ?? "
    elapsed = max(0.001, time.time() - t0)
    bytes_since_start = done - resumed_from
    speed = bytes_since_start / elapsed
    eta = ((total - done) / speed) if speed > 0 and total > 0 else -1
    sys.stdout.write(
        f"\r  {_CYN}{bar}{_RESET} {pct} | "
        f"{_human_bytes(done):>10} / {_human_bytes(total) if total else '  ???':>10} | "
        f"{_human_bytes(int(speed))}/s | ETA {_format_eta(eta)}"
    )
    sys.stdout.flush()


def _load_model(path: Path, timeout: float = 120.0) -> tuple[int, str]:
    """Ask Swift's AIEngine to load the model at `path`. Blocks until
    load completes or `timeout` seconds elapse. Returns (status, msg).
    Status 0 = loaded, negative = error."""
    sig = _signal_dir()
    done_path = sig / "ai_model_done.txt"
    try:
        done_path.unlink()
    except FileNotFoundError:
        pass

    req_path = sig / "ai_load_model.json"
    tmp = sig / "ai_load_model.json.tmp"
    tmp.write_text(json.dumps({"path": str(path)}), encoding="utf-8")
    tmp.replace(req_path)

    t0 = time.time()
    dots = 0
    while time.time() - t0 < timeout:
        if done_path.exists():
            break
        dots = (dots + 1) % 4
        sys.stdout.write(f"\r{_DIM}  loading{'.' * dots}{' ' * (3 - dots)}{_RESET}")
        sys.stdout.flush()
        time.sleep(0.15)
    sys.stdout.write("\r" + " " * 32 + "\r")
    sys.stdout.flush()

    if not done_path.exists():
        return -99, f"timed out after {int(timeout)}s (AIEngine may not be running)"
    raw = done_path.read_text(encoding="utf-8", errors="replace").splitlines()
    status = int(raw[0]) if raw and raw[0].lstrip("-").isdigit() else -1
    message = raw[1] if len(raw) > 1 else ""
    return status, message


def _list_local_models() -> list[Path]:
    """List GGUFs currently in the local cache dir + the user's default
    model dir. Dedupes by filename."""
    seen: dict[str, Path] = {}
    for d in (_models_dir(),):
        if not d.exists():
            continue
        for p in sorted(d.glob("*.gguf")):
            seen.setdefault(p.name, p)
    return list(seen.values())


def _pull_and_load(spec: str) -> bool:
    """Top-level pull-then-load helper shared by `ai run <spec>` and
    the in-REPL `/pull <spec>` command. Returns True on success."""
    try:
        url, dest = _resolve_spec(spec)
    except ValueError as e:
        print(f"{_RED}  {e}{_RESET}"); return False

    if dest.exists() and dest.stat().st_size > 0:
        print(f"{_DIM}  already cached:{_RESET} {dest} ({_human_bytes(dest.stat().st_size)})")
    else:
        print(f"{_BOLD}Downloading{_RESET} {spec}  {_DIM}→ {dest.name}{_RESET}")
        print(f"{_DIM}  from {url}{_RESET}")
        ok = _download_model(url, dest)
        if not ok:
            return False

    print(f"{_DIM}  loading into llama.cpp…{_RESET}")
    status, msg = _load_model(dest)
    if status == 0:
        print(f"{_GRN}  ✓ {msg}{_RESET}")
        return True
    print(f"{_RED}  load failed ({status}): {msg}{_RESET}")
    return False


# ----------------------------------------------------------------------
# Session state
# ----------------------------------------------------------------------

PermissionMode = str   # one of: "nothing", "allow", "plan", "auto", "bypass"

_MODES = ("nothing", "allow", "plan", "auto", "bypass")
_MODE_HELP = {
    "nothing": "read-only — every write is refused",
    "allow":   "show each edit as a diff, prompt y/n (default)",
    "plan":    "LLM writes a multi-step plan first; user edits it; then apply",
    "auto":    "apply small edits (< 5 lines) automatically, prompt for large",
    "bypass":  "apply every edit automatically, no prompts",
}


@dataclass
class Session:
    target: Optional[Path] = None
    history: list = field(default_factory=list)  # list[(role, content)]
    mode: PermissionMode = "allow"
    total_prompt_tokens: int = 0   # rough estimate — we don't get true counts from LlamaRunner
    total_output_tokens: int = 0
    turns: int = 0
    started_at: float = field(default_factory=time.time)


# ----------------------------------------------------------------------
# LLM bridge
# ----------------------------------------------------------------------

def _write_request(messages: list, max_tokens: int = 2048, stop: Optional[list] = None) -> None:
    """Write ai_request.json atomically (tmp + rename)."""
    sig = _signal_dir()
    payload = {"messages": messages, "max_tokens": max_tokens}
    if stop:
        payload["stop"] = stop
    tmp = sig / "ai_request.json.tmp"
    tmp.write_text(json.dumps(payload), encoding="utf-8")
    tmp.replace(sig / "ai_request.json")


def _clear_response_artifacts() -> None:
    sig = _signal_dir()
    for name in ("ai_response.stream", "ai_done.txt"):
        try:
            (sig / name).unlink()
        except FileNotFoundError:
            pass


def _stream_response(on_token: Callable[[str], None],
                     timeout: float = 300.0) -> tuple[int, str]:
    """Tail ai_response.stream, forwarding each chunk to `on_token`.
    Returns (status, message) when ai_done.txt appears."""
    sig = _signal_dir()
    stream_path = sig / "ai_response.stream"
    done_path = sig / "ai_done.txt"

    # Wait for the stream to exist (Swift truncates-creates it at
    # request pickup). Poll cheaply.
    deadline = time.time() + timeout
    while not stream_path.exists() and time.time() < deadline:
        time.sleep(0.05)

    offset = 0
    while time.time() < deadline:
        try:
            size = stream_path.stat().st_size
        except FileNotFoundError:
            size = 0
        if size > offset:
            with stream_path.open("rb") as fh:
                fh.seek(offset)
                chunk = fh.read(size - offset)
            offset = size
            try:
                on_token(chunk.decode("utf-8", errors="replace"))
            except Exception:
                pass
        if done_path.exists():
            # Drain anything the Swift side appended after the last
            # poll before returning — otherwise the last few tokens
            # of a response get truncated.
            try:
                size = stream_path.stat().st_size
                if size > offset:
                    with stream_path.open("rb") as fh:
                        fh.seek(offset)
                        chunk = fh.read(size - offset)
                    on_token(chunk.decode("utf-8", errors="replace"))
            except Exception:
                pass
            raw = done_path.read_text(encoding="utf-8", errors="replace").splitlines()
            status = int(raw[0]) if raw and raw[0].lstrip("-").isdigit() else -1
            message = raw[1] if len(raw) > 1 else ""
            return status, message
        time.sleep(0.06)
    return -99, "timed out after %.0fs" % timeout


# ----------------------------------------------------------------------
# System prompt
# ----------------------------------------------------------------------

_SYSTEM = """You are a coding assistant inside CodeBench, an on-device development workstation for iPad/iPhone/Mac. You help the user read, reason about, and edit source files.

When proposing a change, always emit the full updated file content in a fenced code block tagged with the language, so the host CLI can apply it as a replace. Example:

```python
# updated contents
...
```

Keep explanations short (< 150 words). If the user only asks a question (no change needed), just answer — don't emit a code block.

If the user's request is ambiguous or dangerous (mass delete, network upload, credentials), ask before acting."""


# ----------------------------------------------------------------------
# Edit extraction + application
# ----------------------------------------------------------------------

_CODE_BLOCK_RE = re.compile(
    r"```(?P<lang>[A-Za-z0-9+_\-]*)\s*\n(?P<body>.*?)```",
    re.DOTALL,
)


def _extract_first_code_block(text: str) -> Optional[tuple[str, str]]:
    m = _CODE_BLOCK_RE.search(text)
    if not m:
        return None
    return m.group("lang").lower(), m.group("body")


def _unified_diff(before: str, after: str, filename: str) -> str:
    return "".join(difflib.unified_diff(
        before.splitlines(keepends=True),
        after.splitlines(keepends=True),
        fromfile=filename + " (before)",
        tofile=filename + " (after)",
        n=2,
    ))


def _confirm(prompt: str) -> bool:
    try:
        ans = input(prompt).strip().lower()
    except (KeyboardInterrupt, EOFError):
        print()
        return False
    return ans in ("y", "yes", "")


def _audit(entry: str) -> None:
    try:
        with (_signal_dir() / "ai_audit.log").open("a", encoding="utf-8") as fh:
            fh.write(f"{time.strftime('%Y-%m-%dT%H:%M:%S')}  {entry}\n")
    except OSError:
        pass


def _apply_edit(session: Session, new_content: str) -> bool:
    """Apply a proposed file replacement per current permission mode.
    Returns True if written to disk."""
    target = session.target
    if target is None:
        print(f"{_RED}  no target file — /file <path> to set one{_RESET}")
        return False

    mode = session.mode
    if mode == "nothing":
        print(f"{_DIM}  [mode=nothing] edit refused. /mode allow to enable.{_RESET}")
        return False

    try:
        before = target.read_text(encoding="utf-8", errors="replace") if target.exists() else ""
    except OSError as e:
        print(f"{_RED}  can't read {target}: {e}{_RESET}")
        return False

    if before == new_content:
        print(f"{_DIM}  (no change){_RESET}")
        return False

    diff = _unified_diff(before, new_content, target.name)
    added = sum(1 for line in diff.splitlines() if line.startswith("+") and not line.startswith("+++"))
    removed = sum(1 for line in diff.splitlines() if line.startswith("-") and not line.startswith("---"))
    total = added + removed

    def _show_diff():
        print(f"\n{_DIM}─── diff for {target.name} (+{added}/-{removed}) ───{_RESET}")
        for line in diff.splitlines():
            if line.startswith("+") and not line.startswith("+++"):
                print(f"{_GRN}{line}{_RESET}")
            elif line.startswith("-") and not line.startswith("---"):
                print(f"{_RED}{line}{_RESET}")
            elif line.startswith("@@"):
                print(f"{_CYN}{line}{_RESET}")
            else:
                print(line)
        print(f"{_DIM}────────────────────────────────────{_RESET}")

    # Decide whether to prompt
    if mode == "bypass":
        do_write = True
    elif mode == "auto":
        if total < 5:
            do_write = True  # small
            print(f"{_DIM}  [mode=auto] auto-applying small edit (+{added}/-{removed}){_RESET}")
        else:
            _show_diff()
            do_write = _confirm(f"{_BOLD}apply? [Y/n] {_RESET}")
    elif mode == "plan":
        # Plan mode would have rejected this before we got here; fall
        # through to allow-style prompt as a safety net.
        _show_diff()
        do_write = _confirm(f"{_BOLD}apply? [Y/n] {_RESET}")
    else:  # "allow"
        _show_diff()
        do_write = _confirm(f"{_BOLD}apply? [Y/n] {_RESET}")

    if not do_write:
        print(f"{_YLW}  skipped.{_RESET}")
        return False

    try:
        target.parent.mkdir(parents=True, exist_ok=True)
        target.write_text(new_content, encoding="utf-8")
    except OSError as e:
        print(f"{_RED}  write failed: {e}{_RESET}")
        return False

    print(f"{_GRN}  ✓ wrote {target}  (+{added}/-{removed}){_RESET}")
    _audit(f"edit {target} +{added}/-{removed} mode={mode}")
    # Ping Swift's LaTeXEngine so the Monaco editor's in-memory buffer
    # is refreshed if this file is currently open. Without this, Monaco
    # keeps showing the pre-edit content and its next debounced auto-
    # save overwrites the AI's disk write. Best-effort — the edit IS
    # already on disk; editor refresh is just UX.
    _notify_editor_apply(target, new_content)
    return True


def _notify_editor_apply(path: Path, content: str) -> None:
    """Drop ai_editor_apply.json so Swift can refresh Monaco if the
    file is currently open. Atomic via tmp + rename so the Swift-side
    reader never sees a half-written file."""
    sig = _signal_dir()
    payload = {"path": str(path), "content": content}
    tmp = sig / "ai_editor_apply.json.tmp"
    try:
        tmp.write_text(json.dumps(payload), encoding="utf-8")
        tmp.replace(sig / "ai_editor_apply.json")
    except OSError:
        pass  # best-effort; the disk write already succeeded


# ----------------------------------------------------------------------
# Slash commands
# ----------------------------------------------------------------------

def _slash_help(session: Session, arg: str) -> None:
    print(f"{_BOLD}Slash commands{_RESET}")
    print(f"  {_CYN}/help{_RESET}            this help")
    print(f"  {_CYN}/quit{_RESET} | /exit | /q     leave the CLI")
    print()
    print(f"  {_BOLD}Model management{_RESET}")
    print(f"  {_CYN}/pull [<name>]{_RESET}   download a model (or list the registry)")
    print(f"  {_CYN}/run  <name>{_RESET}     alias of /pull — ollama-style")
    print(f"  {_CYN}/load <path>{_RESET}     load an already-downloaded .gguf")
    print(f"  {_CYN}/model [<name>]{_RESET}  show active model (or load one — alias of /pull)")
    print(f"  {_CYN}/models{_RESET}          list locally-cached GGUFs")
    print()
    print(f"  {_BOLD}Editing{_RESET}")
    print(f"  {_CYN}/file [<path>]{_RESET}   show or switch the current edit target")
    print(f"  {_CYN}/show [<path>]{_RESET}   print the target (or named file) to the terminal")
    print(f"  {_CYN}/ls [<dir>]{_RESET}      list files in current dir (or given dir)")
    print(f"  {_CYN}/mode [<mode>]{_RESET}   permission mode — one of: {', '.join(_MODES)}")
    print()
    print(f"  {_BOLD}Session{_RESET}")
    print(f"  {_CYN}/usage{_RESET}           tokens + turns this session")
    print(f"  {_CYN}/reset{_RESET}           wipe conversation history")
    print(f"  {_CYN}/clear{_RESET}           clear the terminal screen")
    print()
    print(f"{_BOLD}Anything else{_RESET} is sent to the model as a request about the current file.")
    print()
    print(f"{_BOLD}Shell subcommands{_RESET}  {_DIM}(outside the REPL){_RESET}")
    print(f"  {_CYN}ai run <name> [<file>]{_RESET}   download if needed, load, enter REPL")
    print(f"  {_CYN}ai pull <name>{_RESET}           download only")
    print(f"  {_CYN}ai pull{_RESET}                  list the registry")
    print(f"  {_CYN}ai ls{_RESET}                    list cached GGUFs")
    print(f"  {_CYN}ai load <path>{_RESET}           load a GGUF without entering REPL")


def _slash_file(session: Session, arg: str) -> None:
    if not arg:
        if session.target:
            size = session.target.stat().st_size if session.target.exists() else 0
            print(f"{_DIM}current:{_RESET} {session.target}  {_DIM}({size:,} bytes){_RESET}")
        else:
            print(f"{_DIM}  no target — pass a path: /file path/to/thing.py{_RESET}")
        return
    p = Path(os.path.expanduser(arg)).resolve()
    session.target = p
    if p.exists():
        print(f"{_GRN}  target → {p}{_RESET}")
    else:
        print(f"{_YLW}  target → {p}  (file doesn't exist yet; will be created on first edit){_RESET}")


def _slash_show(session: Session, arg: str) -> None:
    p = Path(os.path.expanduser(arg)).resolve() if arg else session.target
    if p is None:
        print(f"{_RED}  no file{_RESET}"); return
    try:
        content = p.read_text(encoding="utf-8", errors="replace")
    except OSError as e:
        print(f"{_RED}  can't read {p}: {e}{_RESET}"); return
    print(f"{_DIM}─── {p} ───{_RESET}")
    print(content.rstrip())
    print(f"{_DIM}─── end ───{_RESET}")


def _slash_ls(session: Session, arg: str) -> None:
    p = Path(os.path.expanduser(arg)).resolve() if arg else Path.cwd()
    if not p.exists():
        print(f"{_RED}  no such dir: {p}{_RESET}"); return
    for item in sorted(p.iterdir(), key=lambda x: (not x.is_dir(), x.name.lower())):
        if item.name.startswith("."): continue
        mark = "/" if item.is_dir() else ""
        size = "" if item.is_dir() else f"  {_DIM}{item.stat().st_size:>10,}b{_RESET}"
        print(f"  {item.name}{mark}{size}")


def _slash_mode(session: Session, arg: str) -> None:
    if not arg:
        print(f"{_BOLD}current mode:{_RESET} {_CYN}{session.mode}{_RESET} — {_MODE_HELP[session.mode]}")
        print(f"{_DIM}  options:{_RESET}")
        for m in _MODES:
            marker = "● " if m == session.mode else "  "
            print(f"  {marker}{_CYN}{m:<8}{_RESET}  {_MODE_HELP[m]}")
        return
    if arg not in _MODES:
        print(f"{_RED}  unknown mode: {arg}{_RESET}")
        print(f"{_DIM}  valid: {', '.join(_MODES)}{_RESET}")
        return
    old = session.mode
    session.mode = arg
    print(f"{_GRN}  mode:{_RESET} {old} → {_CYN}{arg}{_RESET}  {_DIM}({_MODE_HELP[arg]}){_RESET}")
    _audit(f"mode-change {old} → {arg}")


def _slash_model(session: Session, arg: str) -> None:
    """`/model` with no arg shows the loaded model. With an arg,
    resolves it to a local or remote GGUF and loads it (downloading
    first if needed) — shorthand for `/pull <name>`."""
    if arg:
        _pull_and_load(arg)
        return
    p = _signal_dir() / "current_model.txt"
    if p.exists():
        lines = p.read_text(encoding="utf-8").rstrip().splitlines()
        if lines:
            print(f"{_BOLD}active:{_RESET} {_CYN}{lines[0]}{_RESET}")
            if len(lines) >= 2:
                print(f"  {_DIM}path:{_RESET} {lines[1]}")
            if len(lines) >= 3 and lines[2].isdigit():
                print(f"  {_DIM}size:{_RESET} {_human_bytes(int(lines[2]))}")
        return
    print(f"{_DIM}  no model loaded.{_RESET}")
    print(f"{_DIM}  try `/pull qwen2.5:0.5b` or `/pull <name>` — `/pull` with no args lists the registry{_RESET}")


def _slash_pull(session: Session, arg: str) -> None:
    """Download + load a GGUF. `/pull` alone lists the registry."""
    if not arg:
        _list_registry()
        print(f"{_DIM}  local cache:{_RESET} {_models_dir()}")
        local = _list_local_models()
        if local:
            print(f"{_DIM}  cached:{_RESET} " + ", ".join(p.name for p in local))
        return
    _pull_and_load(arg.strip())


def _slash_load(session: Session, arg: str) -> None:
    """Load a GGUF that's already on disk (no download)."""
    if not arg:
        print(f"{_RED}  usage: /load <path-to-gguf>{_RESET}"); return
    p = Path(os.path.expanduser(arg.strip())).resolve()
    if not p.exists():
        print(f"{_RED}  no such file: {p}{_RESET}"); return
    status, msg = _load_model(p)
    if status == 0:
        print(f"{_GRN}  ✓ {msg}{_RESET}")
    else:
        print(f"{_RED}  load failed ({status}): {msg}{_RESET}")


def _slash_models(session: Session, arg: str) -> None:
    """List cached local GGUFs (not the registry; that's `/pull`)."""
    local = _list_local_models()
    if not local:
        print(f"{_DIM}  no cached models in {_models_dir()}{_RESET}")
        print(f"{_DIM}  /pull <name> to fetch one — /pull alone for the list{_RESET}")
        return
    active = ""
    cp = _signal_dir() / "current_model.txt"
    if cp.exists():
        first = cp.read_text(encoding="utf-8").splitlines()
        if first:
            active = first[0]
    print(f"{_BOLD}Local GGUFs{_RESET}  {_DIM}({_models_dir()}){_RESET}")
    for p in local:
        marker = "●" if active and p.stem == active else " "
        sz = _human_bytes(p.stat().st_size)
        print(f"  {marker} {_CYN}{p.name:<40}{_RESET}  {_DIM}{sz}{_RESET}")


def _slash_usage(session: Session, arg: str) -> None:
    elapsed = time.time() - session.started_at
    mins, secs = divmod(int(elapsed), 60)
    print(f"{_BOLD}Session usage{_RESET}")
    print(f"  turns:         {session.turns}")
    print(f"  prompt chars:  {session.total_prompt_tokens:,}  {_DIM}(≈ chars, not tokens){_RESET}")
    print(f"  output chars:  {session.total_output_tokens:,}")
    print(f"  mode:          {session.mode}")
    print(f"  target:        {session.target or '(none)'}")
    print(f"  elapsed:       {mins}m {secs}s")


def _slash_reset(session: Session, arg: str) -> None:
    session.history.clear()
    print(f"{_GRN}  conversation history cleared.{_RESET}")


def _slash_clear(session: Session, arg: str) -> None:
    sys.stdout.write("\033[2J\033[H")
    sys.stdout.flush()


_SLASH = {
    "/help":   _slash_help,
    "/h":      _slash_help,
    "/?":      _slash_help,
    "/quit":   None, "/exit": None, "/q": None,  # handled in loop
    "/file":   _slash_file,
    "/show":   _slash_show,
    "/cat":    _slash_show,
    "/ls":     _slash_ls,
    "/mode":   _slash_mode,
    "/model":  _slash_model,
    "/pull":   _slash_pull,
    "/run":    _slash_pull,   # alias — `run` feels natural to Ollama users
    "/load":   _slash_load,
    "/models": _slash_models,
    "/usage":  _slash_usage,
    "/reset":  _slash_reset,
    "/clear":  _slash_clear,
}


# ----------------------------------------------------------------------
# Main entry
# ----------------------------------------------------------------------

def _default_target() -> Optional[Path]:
    """Read the currently-open editor file path from the shared
    signal file that Swift updates on every file load. If the editor
    has no file loaded, create a scratch file in the workspace and
    ask Swift to open it — that way `ai` always has a target, and
    the user can see / keep editing the scratch file in Monaco."""
    p = _signal_dir() / "current_editor_file.txt"
    if p.exists():
        txt = p.read_text(encoding="utf-8").strip()
        if txt and Path(txt).exists():
            return Path(txt)

    # No file loaded. Create ~/Documents/Workspace/scratch.py (or
    # reuse an existing one) and ask Swift to open it in the editor.
    # Users who prefer an explicit file can always override with
    # /file <path> or run `ai some_file.py`.
    workspace = Path.home() / "Documents" / "Workspace"
    workspace.mkdir(parents=True, exist_ok=True)
    scratch = workspace / "scratch.py"
    if not scratch.exists() or scratch.stat().st_size == 0:
        scratch.write_text(
            '"""Scratch file for CodeBench AI.\n\n'
            'Edit this file from the AI CLI via `ai` or the editor panel.\n'
            'Delete or rename freely — `ai` will recreate it next time\n'
            "it can't find a file to target.\n"
            '"""\n', encoding="utf-8")

    # Tell Swift to load this in the editor so the on-screen panel
    # matches the AI's target. Best-effort — if Swift isn't watching
    # yet, the file is still on disk and the user can open it
    # manually from the file browser.
    try:
        sig = _signal_dir()
        tmp = sig / "open_in_editor.txt.tmp"
        tmp.write_text(str(scratch) + "\n", encoding="utf-8")
        tmp.replace(sig / "open_in_editor.txt")
    except OSError:
        pass

    return scratch


def _build_messages(session: Session, user_input: str) -> list[dict]:
    msgs: list[dict] = [{"role": "system", "content": _SYSTEM}]
    msgs.extend(session.history)

    # Current file context
    if session.target and session.target.exists():
        try:
            body = session.target.read_text(encoding="utf-8", errors="replace")
            ext = session.target.suffix.lstrip(".")
            lang_hint = {"py": "python", "swift": "swift", "c": "c", "cpp": "cpp",
                         "cc": "cpp", "h": "c", "hpp": "cpp", "rs": "rust",
                         "go": "go", "ts": "typescript", "js": "javascript",
                         "java": "java", "m": "objectivec", "mm": "objectivec++",
                         "f90": "fortran", "f95": "fortran", "tex": "latex",
                         "md": "markdown", "html": "html", "css": "css",
                         "json": "json", "yaml": "yaml", "sh": "bash"}.get(ext, ext or "")
            msgs.append({
                "role": "user",
                "content": (
                    f"Here is the current content of `{session.target.name}`:\n\n"
                    f"```{lang_hint}\n{body}\n```\n\n"
                    f"{user_input}"
                ),
            })
        except OSError:
            msgs.append({"role": "user", "content": user_input})
    else:
        msgs.append({"role": "user", "content": user_input})
    return msgs


def run(argv: list[str]) -> None:
    """Entry point called by the shell's `ai` builtin."""
    session = Session()

    # Subcommand dispatch — `ai run <model>`, `ai pull <model>`,
    # `ai ls`, `ai load <path>`. Anything else (or `ai`) drops
    # straight into the REPL.
    if argv:
        sub = argv[0].lower()
        rest = argv[1:]
        if sub == "pull":
            if not rest:
                _list_registry()
                return
            _pull_and_load(rest[0]) if False else None  # (no load on pure pull)
            try:
                url, dest = _resolve_spec(rest[0])
            except ValueError as e:
                print(f"{_RED}ai pull: {e}{_RESET}"); return
            if dest.exists() and dest.stat().st_size > 0:
                print(f"{_DIM}already cached:{_RESET} {dest}")
                return
            print(f"{_BOLD}Downloading{_RESET} {rest[0]}  {_DIM}→ {dest.name}{_RESET}")
            _download_model(url, dest)
            return
        if sub == "run":
            if not rest:
                print(f"{_RED}usage:{_RESET} ai run <model>  {_DIM}(or a direct .gguf URL){_RESET}")
                print(f"{_DIM}  `ai pull` with no args lists known models.{_RESET}")
                return
            ok = _pull_and_load(rest[0])
            if not ok:
                return
            # Fall through into REPL with the model loaded
            argv = rest[1:]  # remaining args are maybe a file to edit
        elif sub in ("ls", "list", "models"):
            local = _list_local_models()
            if not local:
                print(f"{_DIM}no models in {_models_dir()}{_RESET}")
                print(f"{_DIM}  try `ai pull <name>` — `ai pull` with no args lists known models{_RESET}")
                return
            print(f"{_BOLD}Local models{_RESET}  {_DIM}({_models_dir()}){_RESET}")
            for p in local:
                sz = p.stat().st_size
                print(f"  {_CYN}{p.name}{_RESET}  {_DIM}({_human_bytes(sz)}){_RESET}")
            return
        elif sub == "load":
            if not rest:
                print(f"{_RED}usage:{_RESET} ai load <path-to-gguf>")
                return
            p = Path(os.path.expanduser(rest[0])).resolve()
            if not p.exists():
                print(f"{_RED}ai load: no such file: {p}{_RESET}"); return
            status, msg = _load_model(p)
            print(f"{_GRN if status == 0 else _RED}  {msg}{_RESET}")
            return
        # else — treat argv[0] as a target file path and fall through

    # Resolve target
    if argv:
        session.target = Path(os.path.expanduser(argv[0])).resolve()
    else:
        session.target = _default_target()

    # Banner
    banner = f"{_MAG}{_BOLD}CodeBench AI{_RESET}  {_DIM}(local model via llama.cpp){_RESET}"
    print(banner)
    if session.target:
        print(f"{_DIM}target:{_RESET} {session.target}")
    else:
        print(f"{_DIM}no current file — use /file <path> to set one{_RESET}")
    print(f"{_DIM}mode:{_RESET} {_CYN}{session.mode}{_RESET}  {_DIM}· /help for commands · /quit to exit{_RESET}")
    print()

    while True:
        try:
            line = input(f"{_CYN}ai>{_RESET} ")
        except EOFError:
            print()
            break
        except KeyboardInterrupt:
            print(f"\n{_YLW}^C  (type /quit to exit){_RESET}")
            continue

        line = line.strip()
        if not line:
            continue
        if line in ("/quit", "/exit", "/q", "exit", "quit"):
            print(f"{_DIM}goodbye — {session.turns} turn{'s' if session.turns != 1 else ''}{_RESET}")
            break

        # Slash command dispatch
        if line.startswith("/"):
            parts = line.split(None, 1)
            cmd = parts[0]
            arg = parts[1] if len(parts) > 1 else ""
            handler = _SLASH.get(cmd)
            if handler is None:
                print(f"{_RED}unknown command: {cmd}{_RESET}  {_DIM}— /help for list{_RESET}")
            else:
                handler(session, arg)
            continue

        # Plan mode: two-step interaction
        if session.mode == "plan":
            _run_plan_mode(session, line)
        else:
            _run_normal_turn(session, line)

    print()


def _run_normal_turn(session: Session, user_input: str) -> None:
    messages = _build_messages(session, user_input)
    session.total_prompt_tokens += sum(len(m["content"]) for m in messages)
    session.turns += 1

    _clear_response_artifacts()
    _write_request(messages, max_tokens=2048)

    print()  # blank line before response
    collected: list[str] = []
    def on_token(chunk: str) -> None:
        sys.stdout.write(chunk)
        sys.stdout.flush()
        collected.append(chunk)

    status, message = _stream_response(on_token, timeout=600.0)
    print()  # newline after response

    if status != 0:
        print(f"{_RED}  [error {status}]{_RESET} {message}")
        return

    full = "".join(collected)
    session.total_output_tokens += len(full)
    session.history.append({"role": "user", "content": user_input})
    session.history.append({"role": "assistant", "content": full})

    # Look for a code block to apply
    block = _extract_first_code_block(full)
    if block is not None:
        _lang, body = block
        # Only treat as an edit if the block looks like complete code,
        # not a short snippet quote. Heuristic: >= 80% of the original
        # file's lines OR >= 10 lines total.
        lines = body.count("\n")
        if lines >= 10 or (session.target and session.target.exists()
                           and body.count("\n") >= session.target.read_text(errors="replace").count("\n") * 0.5):
            _apply_edit(session, body)


def _run_plan_mode(session: Session, user_input: str) -> None:
    """Plan-first workflow: ask for a plan, let user edit it, then execute."""
    plan_prompt = (
        f"Plan mode: before writing any code, produce a numbered plan of steps you'd "
        f"take to accomplish this request. Do NOT include code blocks yet. Request:\n\n"
        f"{user_input}"
    )
    messages = _build_messages(session, plan_prompt)
    session.turns += 1
    _clear_response_artifacts()
    _write_request(messages, max_tokens=1024)

    print()
    buf: list[str] = []
    def on_token(chunk: str) -> None:
        sys.stdout.write(chunk); sys.stdout.flush(); buf.append(chunk)
    status, msg = _stream_response(on_token, timeout=300.0)
    print()
    if status != 0:
        print(f"{_RED}  [plan error {status}]{_RESET} {msg}"); return

    plan_text = "".join(buf)
    session.history.append({"role": "user", "content": plan_prompt})
    session.history.append({"role": "assistant", "content": plan_text})

    print(f"\n{_DIM}─── edit the plan (blank line or Ctrl+D to submit; /cancel to abort) ───{_RESET}")
    try:
        edited_lines: list[str] = []
        while True:
            try:
                piece = input("> ")
            except EOFError:
                break
            if piece == "/cancel":
                print(f"{_YLW}  plan cancelled.{_RESET}")
                return
            if not piece and edited_lines:
                break
            edited_lines.append(piece)
        final_plan = "\n".join(edited_lines).strip() or plan_text
    except KeyboardInterrupt:
        print(f"\n{_YLW}  plan cancelled.{_RESET}"); return

    # Execute: ask for the code in allow-mode for the apply step
    exec_prompt = (
        f"Execute this plan. Produce the full updated file content in a single "
        f"fenced code block tagged with the language.\n\nPlan:\n{final_plan}"
    )
    old_mode = session.mode
    session.mode = "allow"
    try:
        _run_normal_turn(session, exec_prompt)
    finally:
        session.mode = old_mode
